async (params, browser) => {
  // Open video page
  await browser.open(`${params.video_url}`)

  // Wait for video to load
  await browser.waitForSelector('#title h1, h1.ytd-watch-metadata yt-formatted-string', 15000)

  await browser.wait(2000)

  // Scroll down to trigger comments loading
  await browser.scroll({ direction: 'down', amount: 1200 })

  // Wait for comments section to load
  await browser.wait(3000)

  // Scroll more to load additional comments
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(2000)

  // Scroll for even more comments
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(2000)

  // Extract comments
  const comments_data = await browser.evaluate(`const comments = []; const commentEls = document.querySelectorAll('ytd-comment-thread-renderer'); for (let i = 0; i < Math.min(commentEls.length, 20); i++) { const el = commentEls[i]; const authorEl = el.querySelector('#author-text span, #author-text'); const contentEl = el.querySelector('#content-text, yt-attributed-string#content-text'); const likesEl = el.querySelector('#vote-count-middle, span.vote-count-middle'); const timeEl = el.querySelector('#header-author .published-time-text a, yt-formatted-string.published-time-text a'); const pinnedEl = el.querySelector('#pinned-comment-badge'); const heartEl = el.querySelector('#creator-heart-button ytd-creator-heart-renderer[is-hearted]'); comments.push({ author: authorEl ? authorEl.textContent.trim() : 'Anonymous', content: contentEl ? contentEl.textContent.trim().substring(0, 500) : '', likes: likesEl ? likesEl.textContent.trim() : '0', time: timeEl ? timeEl.textContent.trim() : '', is_pinned: !!pinnedEl, has_heart: !!heartEl }); } const commentCountEl = document.querySelector('#count yt-formatted-string span, h2#count yt-formatted-string'); return { total_comment_count: commentCountEl ? commentCountEl.textContent.trim() : '', scraped_count: comments.length, comments: comments }`)

  return comments_data
}
